<span class="line"><span style="--shiki-light:#4078F2;--shiki-dark:#61AFEF;">claude</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> mcp</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> add</span><span style="--shiki-light:#986801;--shiki-dark:#D19A66;"> --transport</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> http</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> sentry</span><span style="--shiki-light:#50A14F;--shiki-dark:#98C379;"> https://mcp.sentry.dev/mcp</span><span style="--shiki-light:#0184BC;--shiki-dark:#56B6C2;"> \\</span></span>
